const body = $input.first().json.body ?? {};

const requiredFields = [
  'user_id',
  'username',
  'first_name',
  'service_id',
  'service_name',
  'master_id',
  'master_name',
  'date',
  'time',
  'price',
];

const isEmpty = (value) => value === undefined || value === null || value === '';
const missing = requiredFields.filter((field) => isEmpty(body[field]));

const payload = {
  user_id: body.user_id,
  username: body.username,
  first_name: body.first_name,
  service_id: body.service_id,
  service_name: body.service_name,
  master_id: body.master_id,
  master_name: body.master_name,
  date: body.date,
  time: body.time,
  price: Number(body.price),
};

const valid = missing.length === 0 && Number.isFinite(payload.price);
if (missing.length === 0 && !Number.isFinite(payload.price)) {
  missing.push('price');
}

return [{
  json: {
    valid,
    missing,
    payload,
    response: valid
      ? { success: true, message: 'Booking received' }
      : { success: false, message: 'Missing required fields', missing },
  },
}];

// TODO: PostgreSQL insert will be added after this validation step in the next stage.
// TODO: Payment status validation will be added before sending final success responses.

